     * Only allows common SQL data types with optional size parameters.
     *
     * @param columnType The column type to validate
     * @return true if valid, false otherwise
     */
    private boolean isValidColumnType(String columnType) {
        if (columnType == null || columnType.trim().isEmpty()) {
            return false;
        }
        // Allow common SQL types with optional parameters (e.g., VARCHAR(255), DECIMAL(10,2))
        return columnType.matches("^[A-Za-z]+(\\([0-9, ]+\\))?$");
    }
}
